import torchfrom diffusers import DiffusionPipeline, DPMSolverMultistepSchedulerfrom PIL import Imagedevice = "cuda" if torch.cuda.is_available() else "cpu"print(f"Using device: {device}")print(f"GPU: {torch.cuda.get_device_name(0) if torch.cuda.is_available() else 'None'}")repo_id = "sd2-community/stable-diffusion-2-base"pipe = DiffusionPipeline.from_pretrained(    repo_id,    torch_dtype=torch.float16,    variant="fp16")pipe.scheduler = DPMSolverMultistepScheduler.from_config(pipe.scheduler.config)pipe = pipe.to(device)prompt = "a photo of a work desk"image = pipe(prompt, num_inference_steps=25).images[0]image.save("test_output.png")print("Done! Saved to test_output.png")